package graphql_test

import (
	"bytes"
	"context"
	"encoding/json"
	"net/http/httptest"
	"strings"
	"testing"

	"github.com/99designs/gqlgen/graphql/handler"
	"github.com/99designs/gqlgen/graphql/handler/transport"
	ddxgraphql "github.com/DocumentDrivenDX/ddx/internal/server/graphql"
	"github.com/gorilla/websocket"
	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestGraphQLNoPanicOnAnyQueryField verifies that all root Query fields
// return structured GraphQL errors instead of causing panics when a resolver
// panics. This test uses introspection to discover all root Query fields and
// issues a minimal selection against each one.
func TestGraphQLNoPanicOnAnyQueryField(t *testing.T) {
	// Build handler with panic recovery enabled
	gqlSrv := handler.New(ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
		Resolvers: &ddxgraphql.Resolver{
			State:      &testStateProvider{},
			WorkingDir: t.TempDir(),
			Actions:    testActionDispatcher{},
		},
		Directives: ddxgraphql.DirectiveRoot{},
	}))
	gqlSrv.AddTransport(transport.POST{})
	gqlSrv.AddTransport(transport.GET{})
	gqlSrv.AddTransport(transport.Websocket{
		Upgrader: websocket.Upgrader{
			CheckOrigin: func(r *http.Request) bool { return true },
		},
	})
	gqlSrv.SetRecoverFunc(func(ctx context.Context, err interface{}) error {
		return fmt.Errorf("resolver panic: %v", err)
	})

	// Introspection query to discover all root Query fields
	introspectionQuery := `{
		__type(name: "Query") {
			fields {
				name
				args {
					name
					type {
						kind
						ofType {
							name
						}
					}
				}
			}
		}
	}`

	body, _ := json.Marshal(map[string]string{"query": introspectionQuery})
	req := httptest.NewRequest("POST", "/graphql", bytes.NewReader(body))
	req.Header.Set("Content-Type", "application/json")
	w := httptest.NewRecorder()
	gqlSrv.ServeHTTP(w, req)

	var introspectResp struct {
		Data struct {
			Type struct {
				Fields []struct {
					Name string `json:"name"`
					Args []struct {
						Name string `json:"name"`
						Type struct {
							Kind   string `json:"kind"`
							OfType struct {
								Name string `json:"name"`
							} `json:"ofType"`
						} `json:"type"`
					} `json:"args"`
				} `json:"fields"`
			} `json:"__type"`
		} `json:"data"`
		Errors []map[string]interface{} `json:"errors"`
	}

	err := json.Unmarshal(w.Body.Bytes(), &introspectResp)
	require.NoError(t, err, "introspection query should parse successfully")
	require.Empty(t, introspectResp.Errors, "introspection query should not have errors")

	fields := introspectResp.Data.Type.Fields
	require.Greater(t, len(fields), 0, "Query type should have fields")

	// Test each field with a minimal query (except mutations/subscriptions)
	testedCount := 0
	for _, field := range fields {
		// Build a minimal query for this field
		fieldQuery := buildMinimalFieldQuery(field.Name, field.Args)
		if fieldQuery == "" {
			// Skip fields we can't test simply
			continue
		}

		testedCount++
		body, _ := json.Marshal(map[string]string{"query": fieldQuery})
		req := httptest.NewRequest("POST", "/graphql", bytes.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		w := httptest.NewRecorder()
		gqlSrv.ServeHTTP(w, req)

		// Parse response
		var resp struct {
			Data   map[string]interface{} `json:"data"`
			Errors []map[string]interface{} `json:"errors"`
		}
		err := json.Unmarshal(w.Body.Bytes(), &resp)
		require.NoError(t, err, "field %s should return valid JSON", field.Name)

		// Verify either we got data or we got a structured GraphQL error,
		// but NOT an HTTP error or opaque "internal system error"
		assert.NotEqual(t, http.StatusInternalServerError, w.Code,
			"field %s should not return HTTP 500 on panic", field.Name)

		// If there are errors, verify they're properly structured GraphQL errors
		// (not raw panic stack traces)
		for _, graphqlErr := range resp.Errors {
			msg := graphqlErr["message"]
			assert.NotContains(t, msg, "internal system error",
				"field %s should not return opaque internal system error", field.Name)
			assert.NotContains(t, msg, "goroutine",
				"field %s should not leak panic stack traces", field.Name)
		}
	}

	require.Greater(t, testedCount, 10, "should have tested at least 10 fields")
}

// buildMinimalFieldQuery constructs a minimal GraphQL query for a field,
// returning empty string if the field cannot be easily tested.
func buildMinimalFieldQuery(fieldName string, args []struct {
	Name string `json:"name"`
	Type struct {
		Kind   string `json:"kind"`
		OfType struct {
			Name string `json:"name"`
		} `json:"ofType"`
	} `json:"type"`
}) string {
	// Skip fields with required arguments that are complex types
	hasRequiredComplexArg := false
	for _, arg := range args {
		if arg.Type.Kind == "NON_NULL" && arg.Type.OfType.Kind != "SCALAR" && arg.Type.OfType.Kind != "ENUM" {
			hasRequiredComplexArg = true
			break
		}
	}
	if hasRequiredComplexArg {
		return ""
	}

	// Build argument list with minimal defaults
	var argList strings.Builder
	if len(args) > 0 {
		argList.WriteString("(")
		for i, arg := range args {
			if i > 0 {
				argList.WriteString(", ")
			}
			argList.WriteString(arg.Name)
			argList.WriteString(": ")

			// Provide minimal defaults for required arguments
			if arg.Type.Kind == "NON_NULL" {
				switch arg.Type.OfType.Name {
				case "String", "ID":
					argList.WriteString(`"test"`)
				case "Int":
					argList.WriteString("1")
				case "Boolean":
					argList.WriteString("true")
				default:
					// Complex required type we can't easily construct
					return ""
				}
			}
		}
		argList.WriteString(")")
	}

	// Return a minimal field selection
	query := "{ " + fieldName + argList.String()

	// Add a scalar field selection for types that return non-scalars
	// This is a heuristic; adjust as needed for specific types
	switch fieldName {
	case "node", "bead", "documentByPath", "doc", "worker", "agentSession", "persona",
		"execDefinition", "execRun", "execution", "run", "artifact":
